import { TUI_EDITOR_RESIZE_EVENT } from '@taiga-ui/editor/common';
import { tuiDeleteNode } from '@taiga-ui/editor/utils';
import { mergeAttributes } from '@tiptap/core';
import { Details } from '@tiptap/extension-details';
import { DetailsContent } from '@tiptap/extension-details-content';
import { DetailsSummary } from '@tiptap/extension-details-summary';

// TODO: rename to TuiDetails in v5
const TuiDetailsExtension = Details.extend({
  addOptions() {
    return {
      // eslint-disable-next-line @typescript-eslint/no-unnecessary-condition
      ...this.parent?.(),
      inheritOpen: false
    };
  },
  addAttributes() {
    return {
      open: {
        default: 'open',
        keepOnSplit: false,
        parseHTML: element => element.getAttribute('open') === 'open' || element.getAttribute('open') === 'true' || element.hasAttribute('open') || element.getAttribute('data-opened'),
        renderHTML: attributes => ({
          open: attributes.open && this.options.inheritOpen ? 'open' : undefined
        })
      }
    };
  },
  renderHTML({
    HTMLAttributes
  }) {
    return ['details', mergeAttributes(this.options.HTMLAttributes, HTMLAttributes), 0];
  },
  addNodeView() {
    return ({
      node,
      getPos,
      editor
    }) => {
      if (globalThis.document) {
        const wrapper = document.createElement('div');
        const details = document.createElement('details');
        const collapseButton = document.createElement('button');
        const deleteButton = document.createElement('button');
        wrapper.className = 't-details-wrapper';
        collapseButton.className = 't-details-arrow';
        collapseButton.type = 'button';
        deleteButton.className = 't-details-delete';
        deleteButton.type = 'button';
        details.open = node.attrs.open;
        const openHandler = event => {
          const pos = getPos?.() ?? 0;
          details.open = !details.open;
          node.attrs.open = details.open;
          event.target?.dispatchEvent(new CustomEvent(TUI_EDITOR_RESIZE_EVENT, {
            bubbles: true
          }));
          editor.chain().focus().setTextSelection(pos).run();
        };
        collapseButton.addEventListener('click', openHandler);
        deleteButton.addEventListener('click', e => {
          collapseButton.removeEventListener('click', openHandler);
          editor.commands.unsetDetails();
          e.preventDefault();
        }, {
          capture: true,
          once: true
        });
        wrapper.append(details, collapseButton, deleteButton);
        return {
          dom: wrapper,
          contentDOM: details
        };
      }
    };
  },
  addCommands() {
    return {
      ...this.parent?.(),
      setDetails: () => {
        return ({
          commands,
          editor,
          state
        }) => {
          if (editor.isActive('detailsSummary')) {
            return false;
          }
          const {
            schema,
            selection
          } = state;
          const {
            $from,
            $to
          } = selection;
          const range = $from.blockRange($to);
          if (!range) {
            return false;
          }
          const slice = state.doc.slice(range.start, range.end);
          const match = schema.nodes.detailsContent?.contentMatch.matchFragment(slice.content);
          if (!match) {
            return false;
          }
          commands.insertContentAt({
            from: range.start,
            to: range.end
          }, {
            type: this.name,
            content: [{
              type: 'detailsSummary',
              content: [{
                type: 'paragraph',
                content: []
              }]
            }, {
              type: 'detailsContent',
              content: slice.toJSON()?.content ?? []
            }]
          });
          commands.focus();
          commands.setTextSelection(range.start + 2);
          return true;
        };
      },
      unsetDetails: () => ({
        state,
        dispatch
      }) => tuiDeleteNode(state, dispatch, this.name)
    };
  }
});
const TuiDetailsSummary = DetailsSummary.extend({
  content: 'block+',
  group: 'block'
});
/**
 * @deprecated use {@link TuiDetailsSummary}
 */
const TuiSummary = TuiDetailsSummary;
const TuiDetailsContent = DetailsContent.extend({
  addNodeView: null,
  parseHTML() {
    return [{
      tag: 'div[data-type="details-content"]'
    }];
  },
  renderHTML({
    HTMLAttributes
  }) {
    return ['div', mergeAttributes(this.options.HTMLAttributes, HTMLAttributes, {
      'data-type': 'details-content'
    }), 0];
  }
});

/**
 * Generated bundle index. Do not edit.
 */

export { TuiDetailsContent, TuiDetailsExtension, TuiDetailsSummary, TuiSummary };
